x <- rawToChar(as.raw(1:255))


y <- this.path:::encode_string(x, quote = "\"")
stopifnot(
    identical(sort(unique(as.integer(charToRaw(y)))), 0x20:0x7e)
)


z <- parse(text = y, keep.source = FALSE)[[1L]]
stopifnot(
    identical(charToRaw(x), charToRaw(z)),
    identical(Encoding(x), Encoding(z))
)


