f <- function (x)
attr(gregexpr("^ *| *$", x, perl = TRUE)[[1L]], "match.length")


stopifnot(
    identical(f(this.path:::encode_string(x, width = 1001, justify = "left"  )), c(  0L, 279L)),
    identical(f(this.path:::encode_string(x, width = 1001, justify = "right" )), c(279L,   0L)),
    identical(f(this.path:::encode_string(x, width = 1001, justify = "centre")), c(139L, 140L))
)
